import '@testing-library/jest-dom';
// This file was generated by an AI agent. Do not edit directly.
import * as React from 'react';
import { render, screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { MagnifyingGlassIcon, CheckIcon } from '@radix-ui/react-icons';
import { Textarea } from './Textarea';

describe('Textarea rendering', () => {
  it('renders a textbox with the provided label', () => {
    render(<Textarea label="Message" />);
    expect(screen.getByRole('textbox', { name: /message/i })).toBeInTheDocument();
  });

  it('uses ariaLabel when label is missing', () => {
    render(<Textarea ariaLabel="Support request" />);
    expect(screen.getByRole('textbox', { name: /support request/i })).toBeInTheDocument();
  });

  it('honors a user-provided aria-label attribute', () => {
    render(<Textarea aria-label="Custom label" />);
    expect(screen.getByRole('textbox', { name: /custom label/i })).toBeInTheDocument();
  });

  it('prefers the visible label when both label and ariaLabel are provided', () => {
    render(<Textarea label="Primary message" ariaLabel="Secondary" />);
    expect(screen.getByRole('textbox', { name: /primary message/i })).toBeInTheDocument();
  });

  it('renders with an empty accessible name when neither label nor ariaLabel is provided', () => {
    render(<Textarea />);
    const textarea = screen.getByRole('textbox');
    expect(textarea).toHaveAccessibleName('');
  });
});

describe('Textarea native attribute passthrough', () => {
  it('forwards placeholder to the native textarea', () => {
    render(<Textarea label="Message" placeholder="Share details" />);
    const textarea = screen.getByRole('textbox', { name: /message/i });
    expect(textarea).toHaveAttribute('placeholder', 'Share details');
  });

  it('marks the native textarea as required when requested', () => {
    render(<Textarea label="Message" required />);
    const textarea = screen.getByRole('textbox', { name: /message/i });
    expect(textarea).toBeRequired();
  });

  it('merges user-provided aria-describedby with internal ids when info is opened', async () => {
    const user = userEvent.setup();
    render(
      <Textarea
        label="Message"
        info="Additional guidance"
        aria-describedby="external-id"
      />
    );
    await user.click(screen.getByRole('button', { name: 'Message info' }));
    const content = await screen.findByText('Additional guidance');
    const textarea = screen.getByRole('textbox', { name: /message/i });
    const tokens = (textarea.getAttribute('aria-describedby') ?? '').split(' ');
    expect(tokens.includes('external-id') && tokens.includes(content.id ?? '')).toBe(true);
  });
});

describe('Textarea value control', () => {
  it('renders the controlled value', () => {
    render(<Textarea label="Notes" value="Controlled content" readOnly />);
    expect(screen.getByRole('textbox', { name: /notes/i })).toHaveValue('Controlled content');
  });

  it('renders the defaultValue when uncontrolled', () => {
    render(<Textarea label="Notes" defaultValue="Initial draft" />);
    expect(screen.getByRole('textbox', { name: /notes/i })).toHaveValue('Initial draft');
  });
});

describe('Textarea info popover', () => {
  it('renders the info trigger when info text is present', () => {
    render(<Textarea label="Message" info="Additional guidance" />);
    expect(screen.getByRole('button', { name: 'Message info' })).toBeInTheDocument();
  });

  it('merges info content id into aria-describedby when opened', async () => {
    const user = userEvent.setup();
    render(<Textarea label="Message" info="Additional guidance" />);
    await user.click(screen.getByRole('button', { name: 'Message info' }));
    const content = await screen.findByText('Additional guidance');
    const textarea = screen.getByRole('textbox', { name: /message/i });
    expect((textarea.getAttribute('aria-describedby') ?? '').split(' ')).toContain(content.id);
  });

  it('removes the info content id from aria-describedby when the popover closes', async () => {
    const user = userEvent.setup();
    render(<Textarea label="Message" info="Additional guidance" />);
    const trigger = screen.getByRole('button', { name: 'Message info' });
    await user.click(trigger);
    const content = await screen.findByText('Additional guidance');
    const textarea = screen.getByRole('textbox', { name: /message/i });
    await user.keyboard('{Escape}');
    await waitFor(() => {
      expect((textarea.getAttribute('aria-describedby') ?? '').split(' ')).not.toContain(content.id);
    });
  });

  it('restores focus to the info trigger after closing with Escape', async () => {
    const user = userEvent.setup();
    render(<Textarea label="Message" info="Additional guidance" />);
    const trigger = screen.getByRole('button', { name: 'Message info' });
    await user.click(trigger);
    await screen.findByText('Additional guidance');
    await user.keyboard('{Escape}');
    await waitFor(() => {
      expect(document.activeElement).toBe(trigger);
    });
  });
});

describe('Textarea messaging', () => {
  it('renders error instead of hint when both are provided', () => {
    render(<Textarea label="Feedback" hint="Help text" error="Error state" />);
    expect(screen.getByText('Error state')).toBeInTheDocument();
  });

  it('omits the hint slot when an error is provided', () => {
    render(<Textarea label="Feedback" hint="Help text" error="Error state" />);
    expect(document.querySelector('[data-slot="hint"]')).toBeNull();
  });

  it('sets the invalid state on the root when error is present', () => {
    render(<Textarea label="Feedback" error="Error state" />);
    const group = screen.getByRole('group');
    expect(group).toHaveAttribute('data-invalid', 'true');
  });

  it('applies aria-describedby pointing to the rendered error', () => {
    render(<Textarea label="Feedback" error="Error state" />);
    const textarea = screen.getByRole('textbox', { name: /feedback/i });
    const errorElement = document.querySelector('[data-slot="error"]') as HTMLElement;
    expect(textarea.getAttribute('aria-describedby')).toBe(errorElement.id);
  });
});

describe('Textarea icons', () => {
  it('renders the start icon when provided', () => {
    render(<Textarea label="Search" startIcon={<MagnifyingGlassIcon aria-hidden="true" />} />);
    const iconWrapper = document.querySelector('[data-slot="startIcon"]') as HTMLElement;
    expect(iconWrapper.getAttribute('aria-hidden')).toBe('true');
  });

  it('renders the end icon when provided', () => {
    render(<Textarea label="Search" endIcon={<CheckIcon aria-hidden="true" />} />);
    const iconWrapper = document.querySelector('[data-slot="endIcon"]') as HTMLElement;
    expect(iconWrapper.getAttribute('aria-hidden')).toBe('true');
  });
});

describe('Textarea disabled state', () => {
  it('disables the fieldset when disabled is true', () => {
    render(<Textarea label="Message" disabled />);
    expect(screen.getByRole('group')).toBeDisabled();
  });

  it('disables the native textarea when disabled is true', () => {
    render(<Textarea label="Message" disabled />);
    expect(screen.getByRole('textbox', { name: /message/i })).toBeDisabled();
  });
});

describe('Textarea a11y structure', () => {
  it('does not apply aria-describedby to the fieldset root', () => {
    render(<Textarea label="Message" hint="Helpful hint" />);
    const group = screen.getByRole('group');
    expect(group).not.toHaveAttribute('aria-describedby');
  });
});

